responses.body:
{{~setVar 'profile' (find (dataRaw 'profiles') (object username=(bodyRaw 'username')))~}}
{
  "user": {
    "id": "{{@profile.id}}",
    "username": "{{@profile.username}}",
    "name": "{{@profile.name}}",
    "role": "user"
  },
  "accessToken": "{{faker 'internet.jwt' (object header=(object alg='HS256') payload=(object username=@profile.username role='user' id=@profile.id))}}"
}

{{~ setVar 'page' (queryParam "page" 1) ~}}
{{~ setVar 'limit' (queryParam "limit" 10) ~}}
{{~ setVar 'searchKey' (queryParam "searchKey") ~}}
{{~ setVar 'sortParam' (queryParam "sort" "createdAt,desc") ~}}
{{~ setVar 'sortParts' (split @sortParam ',') ~}}
{{~ setVar 'sortField' @sortParts.[0] ~}}
{{~ setVar 'sortDir' (lowercase @sortParts.[1]) ~}}
{{~ setVar 'result' (dataRaw "Articles") ~}}
{{~#if @searchKey}}
  {{~ setVar 'result' (filter @result (object tags=@searchKey) (object title=@searchKey)) ~}}
{{~/if}}
{{~ setVar 'result' (sortBy @result @sortField @sortDir) ~}}
{{~ setVar 'total' (len @result) ~}}
{{~ setVar 'start' (multiply (subtract @page 1) @limit) ~}}
{{~ setVar 'end' (add @start @limit) ~}}
{{~ setVar 'items' (slice @result @start @end) ~}}

{
  "page": {{ @page }},
  "limit": {{ @limit }},
  "total": {{ @total }},
  "lastPage": {{#if (gte @end @total)}}true{{else}}false{{/if}},
  "items": [
    {{#each @items}}
    {
      "id": "{{ this.id }}",
      "title": "{{ this.title }}",
      "description": "{{ this.description }}",
      "preview": "{{ this.preview }}",
      "author": {{{ stringify this.author }}},
      "createdAt": "{{ this.createdAt }}",
      "tags": {{{ stringify this.tags }}},
      "views": {{#if this.views}}{{this.views}}{{else}}0{{/if}}
    }{{#unless @last}},{{/unless}}
    {{/each}}
  ]
}

{{~#if (bodyRaw 'text')~}}
  {{~setVar 'authorId' (jwtPayload (header 'Authorization') 'id')~}}
  {{~setVar 'profile' (find (dataRaw 'profiles') (object id=@authorId))~}}
  {{~setVar 'newComment' (object 
      id=(uuid) 
      author=(object 
          id=@profile.id 
          username=@profile.username 
          photo=@profile.photo
      )
      text=(bodyRaw 'text')
      createdAt=(now 'T')
      articleId=(urlParam 'id')
  )~}}
  {{~setData 'push' 'ArticleComments' '' @newComment~}}
  {{{stringify @newComment}}}
{{~else~}}
  { "error": "Text is required" }
{{~/if~}}

{{~setVar 'userId' (jwtPayload (header 'Authorization') 'id')~}}
{{~setVar 'articleId' (urlParam 'id')~}}
{{~setVar 'existing' (find (dataRaw 'ArticleRates') (object userId=@userId articleId=@articleId))~}}
{{~#if @existing~}}
  {{#each (dataRaw 'ArticleRates')}}
    {{~#if (eq this.userId @userId)~}}
      {{~#if (eq this.articleId @articleId)~}}
        {{~setData 'merge' 'ArticleRates' @index (object
          rating=(bodyRaw 'rating')
          feedback=(bodyRaw 'feedback')
        )~}}
      {{~/if~}}
    {{~/if~}}
  {{/each}}
  {{{stringify (find (dataRaw 'ArticleRates') (object userId=@userId articleId=@articleId))}}}
{{~else~}}
  {{~setVar 'newRate' (object
    id=(uuid)
    rating=(bodyRaw 'rating')
    feedback=(bodyRaw 'feedback')
    userId=@userId
    articleId=@articleId
  )~}}
  {{~setData 'push' 'ArticleRates' '' @newRate~}}
  {{{stringify @newRate}}}
{{~/if~}}

{{~setVar 'userId' (jwtPayload (header 'Authorization') 'id')~}}
{{~setVar 'profileId' (urlParam 'id')~}}
{{~setVar 'existing' (find (dataRaw 'ProfileRates') (object userId=@userId profileId=@profileId))~}}
{{~#if @existing~}}
  {{#each (dataRaw 'ProfileRates')}}
    {{~#if (eq this.userId @userId)~}}
      {{~#if (eq this.profileId @profileId)~}}
        {{~setData 'merge' 'ProfileRates' @index (object
          rating=(bodyRaw 'rating')
          feedback=(bodyRaw 'feedback')
        )~}}
      {{~/if~}}
    {{~/if~}}
  {{/each}}
  {{{stringify (find (dataRaw 'ProfileRates') (object userId=@userId profileId=@profileId))}}}
{{~else~}}
  {{~setVar 'newRate' (object
    id=(uuid)
    rating=(bodyRaw 'rating')
    feedback=(bodyRaw 'feedback')
    userId=@userId
    profileId=@profileId
  )~}}
  {{~setData 'push' 'ProfileRates' '' @newRate~}}
  {{{stringify @newRate}}}
{{~/if~}}

